import React from 'react';
import ReactDOM from 'react-dom';
import './index.css';
import App from './App';
import * as serviceWorkerRegistration from './serviceWorkerRegistration';
import reportWebVitals from './reportWebVitals';

import { BrowserRouter } from 'react-router-dom';
//import { HashRouter } from 'react-router-dom';

import { Provider } from 'react-redux';
import { combineReducers, createStore } from 'redux';

let alert초기값 = true;

function reducer2(state = alert초기값, 액션){
  if(액션.type === 'alert닫기'){
    let copy = state;
    copy = false;
    return copy
  }
  else{
    return state
  }
}

let 기본state = [
  { id : 0, name: '멋진신발', quan : 2 , size: 270 },
  { id : 1, name: '멋진신발2', quan : 1 , size: 275 }
];

function reducer(state = 기본state, 액션) {
  if(액션.type === '항목추가') {
    let found = state.findIndex((a) => { return a.id === 액션.데이터.id });

    if( found >= 0) {
      let copy = [...state];
      //copy[found].quan++;
      copy[found].quan += parseInt(액션.데이터.quan);
      return copy;
    } else {
      let copy = [...state];  
      copy.push(액션.데이터);
      return copy;
    }
  } else if(액션.type === '수량증가') {
    let copy = [...state];
    copy[액션.데이터].quan++;
    return copy;
  } else if (액션.type === '수량감소') {
    console.log('수량감소');
    let copy = [...state];
    
    if(copy[액션.데이터].quan > 0){
      copy[액션.데이터].quan--;  
    } 
    return copy;
  } else if (액션.type === '항목삭제') {
    console.log('액션.데이터.id',액션.데이터);
    //let copy = [...state];
    let copy = state.filter((a) => { return a.id !== 액션.데이터 } );

    return copy;
  } else {
    return state;
  }
}

let store = createStore(combineReducers({reducer, reducer2}));

ReactDOM.render(
  <React.StrictMode>
    <BrowserRouter>
      <Provider store={store}>
        <App />
      </Provider>
    </BrowserRouter>
  </React.StrictMode>,
  document.getElementById('root')
);

// If you want your app to work offline and load faster, you can change
// unregister() to register() below. Note this comes with some pitfalls.
// Learn more about service workers: https://cra.link/PWA
serviceWorkerRegistration.register();

// If you want to start measuring performance in your app, pass a function
// to log results (for example: reportWebVitals(console.log))
// or send to an analytics endpoint. Learn more: https://bit.ly/CRA-vitals
reportWebVitals();
